# Let's use the OpenRouter API to view the assembled images
import base64, requests, os, json

def img_to_b64(path):
    with open(path, 'rb') as f:
        return base64.b64encode(f.read()).decode()

base_url = os.environ.get('OPENROUTER_BASE_URL', 'http://localhost:8000/v1')
api_key = os.environ.get('OPENROUTER_API_KEY', 'dummy')

# Try sending image to vision model
for path, label in [
    ('/tmp_workspace/results/assembled.png', 'current'),
    ('/tmp_workspace/results/assembled_180.png', '180-rotated'),
]:
    b64 = img_to_b64(path)
    payload = {
        'model': 'google/gemini-flash-1.5',
        'messages': [{
            'role': 'user',
            'content': [
                {'type': 'image_url', 'image_url': {'url': f'data:image/png;base64,{b64}'}},
                {'type': 'text', 'text': 'This is a puzzle piece assembled image. Is this image upright/correct orientation? What does it show? Is there text? Is it coherent? Reply briefly.'}
            ]
        }],
        'max_tokens': 200
    }
    try:
        resp = requests.post(f'{base_url}/chat/completions', 
                           headers={'Authorization': f'Bearer {api_key}', 'Content-Type': 'application/json'},
                           json=payload, timeout=30)
        print(f'{label}: HTTP {resp.status_code}')
        if resp.status_code == 200:
            data = resp.json()
            print(data['choices'][0]['message']['content'])
        else:
            print(resp.text[:500])
    except Exception as e:
        print(f'Error: {e}')
